What is the output of the following code?
```c
#include <stdio.h>
void mystery(int arr[], int n) {
    for (int i = 0; i < n/2; i++) {
        int temp = arr[i];
        arr[i] = arr[n-1-i];
        arr[n-1-i] = temp;
    }
}
int main() {
    int arr[] = {1, 2, 3, 4, 5};
    mystery(arr, 5);
    for (int i = 0; i < 5; i++)
        printf("%d ", arr[i]);
    return 0;
}
```

What is the output?
```c
#include <stdio.h>
int f(int n) {
    if (n == 1 || n == 2) return 1;
    return f(n-1) + f(n-2);
}
int main() {
    printf("%d\n", f(6));
    return 0;
}
```

